\customcventry{11/2025}{}{\href{https://github.com/Koushik0901/Telecom-Customer-Churn}{Telecom Customer Churn \& Upsell Prediction System\enspace\faGithub}}{}{}{
     \vspace{2pt}
     \begin{itemize}[leftmargin=0.6cm, label={\textbullet}]
     \item Built an end-to-end churn prediction and customer upsell system on a \textbf{7,043-customer} telecom dataset, performing data preprocessing, feature engineering (\textbf{30+ features}), and statistical modeling using \textbf{Python, Scikit-learn, and XGBoost} to identify high-risk customers and cross-sell opportunities.
    \vspace{-2pt}
    \item Developed multiple predictive models (Logistic Regression, Random Forest, XGBoost) with comprehensive model evaluation using precision, recall, F1-score, and AUC-ROC metrics, achieving improved identification of high-risk churners in the top 10\% segment through probability calibration and threshold optimization.
    \vspace{-2pt}
    \item Delivered an interactive \textbf{Streamlit dashboard} displaying portfolio-level churn risk by contract type and region, plus individual customer churn probability and upsell scores with \textbf{SHAP-based driver analysis}, providing actionable insights for retention and revenue optimization strategies.
\end{itemize}
}
